 }

 .btn-secondary {
   background: rgba(255, 255, 255, 0.05);
   color: white;
   border: 1px solid rgba(255, 255, 255, 0.1);
 }

 .btn-secondary:hover {
   background: rgba(255, 255, 255, 0.1);
 }

 /* Layout Engine */
 .app-container {
   display: flex;
   width: 100vw;
   height: 100vh;
 }

 .board-area {
   flex: 1;
   position: relative;
   display: flex;
   align-items: center;
   justify-content: center;
   overflow: hidden;
 }

 .ledger-area {
   width: 480px;
   background-color: var(--color-bg-ledger);
   border-left: 1px solid rgba(212, 175, 55, 0.1);
   display: flex;
   flex-direction: column;
   z-index: 10;
   box-shadow: -20px 0 50px rgba(0,0,0,0.8);
 }

 /* Mobile Optimization */
 @media (max-width: 1100px) {
   .app-container {
