          {/* Central Interaction Hub */}
          <div className="glass-panel center-hub" style={{ 
            padding: '2.5rem', 
            textAlign: 'center', 
            width: '280px', 
            height: '280px',
            borderRadius: '50%',
            display: 'flex',
            flexDirection: 'column',
            justifyContent: 'center',
            alignItems: 'center',
            gap: '1rem',
            border: '1px solid rgba(255,255,255,0.08)',
            boxShadow: 'inset 0 0 50px rgba(0,0,0,0.5), 0 0 30px rgba(0,0,0,0.5)',
            background: 'rgba(15, 15, 20, 0.4)',
            backdropFilter: 'blur(10px)'
          }}>
            {turnPhase === 'ROLL' || isRolling ? (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '0.8rem', width: '100%', alignItems: 'center' }}>
                <div style={{ display: 'flex', gap: '0.5rem', marginBottom: '0.5rem' }}>
                  {diceRoll.map((v, i) => (
                    <Dice3D key={i} value={v} rolling={isRolling} />
                  ))}
                </div>
                {!currentPlayer.isBot && !isRolling && isMyTurn && (
                  <>
                    <button 
                      className="btn btn-success btn-pop main-roll-btn" 
                      style={{ 
                        width: '100%', 
                        padding: '1.2rem', 
                        borderRadius: '100px', 
                        fontSize: '1.2rem',
                        fontWeight: 900,
                        letterSpacing: '2px',
                        boxShadow: '0 10px 25px rgba(40, 167, 69, 0.3)'
                      }} 
                      onClick={() => {
                        setRolling(true);
                        gameAudio.playSFX('dice');
                        setTimeout(() => {
                          rollDice(1);
                          setRolling(false);
                        }, 1000);
                      }}
                    >
                      ROLL 1 DIE
                    </button>
                    {currentPlayer.charityTurnsRemaining > 0 && (
                      <button 
                        className="btn btn-info btn-pop" 
                        style={{ 
                          width: '100%', 
                          padding: '1rem', 
                          borderRadius: '100px', 
                          fontSize: '0.9rem',
                          fontWeight: 800,
                          background: 'linear-gradient(135deg, #00d2ff 0%, #3a7bd5 100%)',
                          color: 'white',
                          border: 'none'
                        }} 
                        onClick={() => {
                          setRolling(true);
                          gameAudio.playSFX('dice');
                          setTimeout(() => {
                            rollDice(2);
                            setRolling(false);
                          }, 1000);
                        }}
                      >
                        ROLL 2 DICE
                      </button>
                    )}
                  </>
                )}
                {!isMyTurn && !currentPlayer.isBot && !isRolling && (
                  <div style={{ color: 'var(--color-primary)', fontWeight: 800, textTransform: 'uppercase', letterSpacing: '2px', textAlign: 'center' }}>
                    Waiting for {currentPlayer?.name}...
                  </div>
                )}
                {currentPlayer.isBot && isRolling && (
                   <div style={{ color: 'var(--color-primary)', fontWeight: 800, textTransform: 'uppercase', letterSpacing: '2px' }}>AI is rolling...</div>
                )}
              </div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem', alignItems: 'center' }}>
                <div style={{ display: 'flex', gap: '0.5rem', marginBottom: '0.5rem' }}>
                  {diceRoll.map((v, i) => (
                    <Dice3D key={i} value={v} rolling={false} />
                  ))}
                </div>
                <div style={{ fontSize: '0.8rem', opacity: 0.6, textTransform: 'uppercase', letterSpacing: '2px' }}>
                  Landed On
                </div>
                <div style={{ 
                  color: RAT_RACE_SPACES[currentPlayer.position].color, 
                  fontSize: '1.2rem', 
                  fontWeight: 900,
                  textTransform: 'uppercase',
                  letterSpacing: '1px',
                  textAlign: 'center'
                }}>
                  {RAT_RACE_SPACES[currentPlayer.position].label}
                </div>

                <div style={{ width: '100%', marginTop: '1rem', display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                  {!isMyTurn ? (
                    <div className="glass-panel" style={{ padding: '1rem', color: 'var(--color-primary)', fontSize: '0.8rem', textAlign: 'center' }}>
                      {currentPlayer?.name} is playing...
                    </div>
                  ) : (
                    <>
                      {RAT_RACE_SPACES[currentPlayer.position].type === 'OPPORTUNITY' && (
                        <>
                          <button className="btn btn-success btn-pop" style={{ padding: '0.8rem' }} onClick={() => drawCard('SMALL_DEAL')}>
                            SMALL DEAL
                          </button>
                          <button 
                            className="btn btn-success btn-pop" 
                            style={{ padding: '0.8rem', background: '#1b5e20', opacity: currentPlayer.statement.cash < 6000 ? 0.5 : 1 }} 
                            onClick={() => drawCard('BIG_DEAL')}
                          >
                            BIG DEAL
                          </button>
                        </>
                      )}

                      {RAT_RACE_SPACES[currentPlayer.position].type === 'DOODAD' && (
                        <button className="btn btn-pop" style={{ backgroundColor: '#dc3545', color: 'white', padding: '1rem' }} onClick={() => drawCard('DOODAD')}>
                          DRAW DOODAD
                        </button>
                      )}

                      {RAT_RACE_SPACES[currentPlayer.position].type === 'MARKET' && (
                        <button className="btn btn-pop" style={{ backgroundColor: '#007bff', color: 'white', padding: '1rem' }} onClick={() => drawCard('MARKET')}>
                          DRAW MARKET
                        </button>
                      )}

                      {RAT_RACE_SPACES[currentPlayer.position].type === 'BABY' && (
                        <button className="btn btn-pop" style={{ backgroundColor: '#e83e8c', color: 'white', padding: '1rem' }} onClick={() => { useGameStore.getState().haveChild(currentPlayer.id); endTurn(); }}>
                          ADD FAMILY MEMBER
                        </button>
                      )}

                      {RAT_RACE_SPACES[currentPlayer.position].type === 'CHARITY' && (
                        <div style={{ display: 'flex', gap: '0.5rem' }}>
                          <button className="btn btn-pop" style={{ backgroundColor: '#17a2b8', color: 'white', flex: 1, padding: '1rem' }} onClick={() => { useGameStore.getState().donateToCharity(currentPlayer.id); endTurn(); }}>
                            DONATE (10% Income)
                          </button>
                          <button className="btn btn-secondary" style={{ flex: 1 }} onClick={() => endTurn()}>
                            SKIP
                          </button>
                        </div>
                      )}

                      {RAT_RACE_SPACES[currentPlayer.position].type === 'DOWNSIZED' && (
                        <button className="btn btn-pop" style={{ backgroundColor: '#6c757d', color: 'white', padding: '1rem' }} onClick={() => { useGameStore.getState().goDownsized(currentPlayer.id); endTurn(); }}>
                          PAY PENALTY & LOSE 2 TURNS
                        </button>
                      )}

                      {pendingPaydays > 0 && (
                        <button 
                          className="btn btn-pop payday-alert" 
                          style={{ backgroundColor: '#ffd700', color: '#000', fontWeight: 900, padding: '1rem', borderRadius: '100px' }} 
                          onClick={collectPayday}
                        >
                          COLLECT PAYDAY! ({pendingPaydays})
                        </button>
                      )}

                      <button className="btn btn-primary btn-pop" style={{ padding: '0.8rem', marginTop: '0.5rem', opacity: 0.8 }} onClick={() => endTurn()}>
                        END TURN
                      </button>
                    </>
                  )}
                </div>
              </div>
            )}
          </div>
          <CardModal />
        </div>
      </div>
    </div>
    </div>
  );
};

import { useState } from 'react';
import { useGameStore } from '../store/gameStore';
import type { Asset, Player } from '../types/game';
import { getEventTip } from '../data/tips';

export const CardModal = () => {
  const { activeCard, players, currentPlayerIndex, resolveCard, buyAsset, sellAsset, handleMarketEvent, transferDeal, payCash, myPlayerId } = useGameStore();
  const [sharesToBuy, setSharesToBuy] = useState(10);
  const [showPeerTrade, setShowPeerTrade] = useState(false);
  const [targetPlayerId, setTargetPlayerId] = useState('');
  const [tradeFee, setTradeFee] = useState(0);

  const player = players[currentPlayerIndex];

  if (!activeCard || !player) return null;

  // No-op - removed unused eligibleAssets logic

  const handleTrade = () => {
    if (!targetPlayerId) return;
    transferDeal(player.id, targetPlayerId, activeCard, tradeFee);
    resolveCard();
  };

  const renderMarketAction = () => {
    if (activeCard.marketEvent) {
      return (
        <button className="btn btn-primary btn-pop" style={{ width: '100%' }} onClick={() => {
          handleMarketEvent(activeCard.marketEvent);
          resolveCard();
        }}>
          {activeCard.actionText || 'Apply Event'}
        </button>
      );
    }

    // Find ALL players with eligible assets (for Global Market Events)
    const playersWithAssets = players.map((p: any) => ({
      player: p,
      assets: p.statement.assets.filter((a: any) => {
        if (!activeCard.assetType) return false;
        if (activeCard.assetType === 'REAL_ESTATE') {
          return a.type === 'REAL_ESTATE' && activeCard.description.toLowerCase().includes(a.name.split(' ')[0].toLowerCase());
        }
        return a.type === activeCard.assetType && (activeCard.title.includes(a.name) || a.name.includes(activeCard.title.split(' ')[0]));
      })
    })).filter((entry: any) => entry.assets.length > 0);

    return (
      <div className="market-resolution">
        <label className="pencil-text">Market Opportunity:</label>
        {playersWithAssets.length > 0 ? playersWithAssets.map((entry: any) => (
          <div key={entry.player.id} className="player-market-group">
            <div className="player-name-small" style={{ color: entry.player.color }}>{entry.player.name}'s Assets:</div>
            {entry.assets.map((a: Asset) => {
              const calculatePrice = () => {
                let price = activeCard.cost || 0;
                if (activeCard.description.toLowerCase().includes('per unit')) {
                  const unitMatch = a.name.match(/(\d+)\s*Unit/i);
                  if (unitMatch) price = price * parseInt(unitMatch[1]);
                } else if (activeCard.title.includes('3x')) {
                  price = a.cost * 3;
                } else if (a.type === 'STOCK') {
                  price = price * (a.shares || 0);
                }
                return price;
              };
              const price = calculatePrice();
              const isOwner = myPlayerId === 'LOCAL' || entry.player.id === myPlayerId;

              return (
                <div key={a.id} className="asset-sell-row">
                  <span>{a.name}</span>
                  <button 
                    className="btn btn-success small" 
                    disabled={!isOwner}
                    onClick={() => {
                      sellAsset(entry.player.id, a.id, price);
                      if (activeCard.assetType !== 'STOCK') resolveCard(); 
                    }}
                  >
                    {isOwner ? `Sell for $${price.toLocaleString()}` : 'Owner Action'}
                  </button>
                </div>
              );
            })}
          </div>
        )) : <p className="pencil-text small">No one has matching assets.</p>}
        <button className="btn btn-secondary" style={{ width: '100%', marginTop: '1rem' }} onClick={resolveCard}>Done</button>
        <style>{`
          .player-market-group { margin-top: 1rem; border-top: 1px solid rgba(255,255,255,0.05); padding-top: 0.5rem; }
          .player-name-small { font-size: 0.75rem; font-weight: 800; margin-bottom: 0.3rem; text-transform: uppercase; }
        `}</style>
      </div>
    );
  };

  return (
    <div className="modal-overlay animate-fade-in">
      <div className="card-container glass-panel animate-slide-up" data-type={activeCard.type}>
        <div className="card-header">
          <div className="card-badge">{activeCard.type.replace('_', ' ')}</div>
          <h2 className="card-title">{activeCard.title}</h2>
        </div>

        <div className="card-content">
          <p className="card-description">{activeCard.description}</p>

          {activeCard.cost !== undefined && activeCard.type !== 'MARKET' && (
            <div className="stat-row">
              <span className="label">Cost:</span>
              <span className="value">${activeCard.cost.toLocaleString()}</span>
            </div>
          )}

          {activeCard.assetType === 'STOCK' && activeCard.type !== 'MARKET' && (
             <div className="stock-buy-input">
                <label>Shares to Buy:</label>
                <input type="number" value={sharesToBuy} onChange={e => setSharesToBuy(Math.max(1, +e.target.value))} />
                <div className="total-cost">Total: ${(activeCard.cost! * sharesToBuy).toLocaleString()}</div>
             </div>
          )}

          {activeCard.cashflow !== undefined && activeCard.type !== 'MARKET' && (
            <div className="stat-row success">
              <span className="label">Cashflow:</span>
              <span className="value">+${activeCard.cashflow.toLocaleString()}</span>
            </div>
          )}
        </div>

        <div className="card-actions">
          {activeCard.type === 'MARKET' ? renderMarketAction() : (
            <>
              <button 
                className="btn btn-secondary flex-1" 
                disabled={activeCard.type === 'DOODAD' && player.statement.cash < (activeCard.cost || 0)}
                onClick={() => {
                  if (activeCard.type === 'DOODAD') {
                    payCash(player.id, activeCard.cost || 0); 
                  }
                  resolveCard();
                }}
              >
                {activeCard.type === 'DOODAD' ? `Pay $${(activeCard.cost || 0).toLocaleString()}` : 'Pass'}
              </button>

              <button 
                className="btn btn-primary flex-1"
                onClick={() => {
                  const cost = activeCard.assetType === 'STOCK' ? (activeCard.cost! * sharesToBuy) : (activeCard.downPayment || activeCard.cost || 0);
                  if (player.statement.cash >= cost) {
                    buyAsset(player.id, {
                      id: `asset-${Date.now()}`,
                      name: activeCard.assetType === 'STOCK' ? `${activeCard.title.split(':')[1]?.trim() || activeCard.title} (${sharesToBuy})` : activeCard.title,
                      type: activeCard.assetType || 'BUSINESS',
                      cost: activeCard.cost || 0,
                      downPayment: activeCard.downPayment || activeCard.cost || 0,
                      cashflow: activeCard.cashflow || 0,
                      shares: activeCard.assetType === 'STOCK' ? sharesToBuy : undefined,
                      dividend: activeCard.assetType === 'STOCK' ? activeCard.cashflow : undefined
                    });
                    resolveCard();
                  } else {
                    alert('Not enough cash! Borrow from bank.');
                  }
                }}
              >
                {activeCard.actionText || 'Buy'}
              </button>
            </>
          )}
        </div>

        {(activeCard.type === 'SMALL_DEAL' || activeCard.type === 'BIG_DEAL') && (
          <div className="peer-trade-section">
            <button className="btn-link" onClick={() => setShowPeerTrade(!showPeerTrade)}>
              {showPeerTrade ? '✕ Cancel Trade' : '🤝 Sell Deal to Peer'}
            </button>
            {showPeerTrade && (
              <div className="trade-controls animate-fade-in">
                <select value={targetPlayerId} onChange={e => setTargetPlayerId(e.target.value)}>
                  <option value="">Select Player...</option>
                  {players.filter((p: Player) => p.id !== player.id).map((p: Player) => (
                    <option key={p.id} value={p.id}>{p.name}</option>
                  ))}
                </select>
                <input type="number" placeholder="Fee ($)" onChange={e => setTradeFee(+e.target.value)} />
                <button className="btn btn-success small" onClick={handleTrade} disabled={!targetPlayerId}>Transfer</button>
                <button 
                  className="btn btn-info small" 
                  onClick={() => {
                    if (!targetPlayerId) return;
                    transferDeal(player.id, targetPlayerId, activeCard, 0, true);
                    resolveCard();
                  }} 
                  disabled={!targetPlayerId}
                >
                  🤝 Partnership (50/50)
                </button>
              </div>
            )}
          </div>
        )}

        <div className="wealth-tip" style={{ 
          marginTop: '1.5rem', 
          padding: '0.8rem', 
          backgroundColor: 'rgba(255,215,0,0.05)', 
          borderRadius: '12px',
