  display: inline-block;
}

.dice {
  width: 100%;
  height: 100%;
  position: relative;
  transform-style: preserve-3d;
}

.dice-face {
  position: absolute;
  width: 60px;
  height: 60px;
  background: white;
  border: 2px solid #ddd;
  border-radius: 8px;
  display: flex;
  flex-wrap: wrap;
  padding: 8px;
  box-sizing: border-box;
  justify-content: space-between;
  box-shadow: inset 0 0 10px rgba(0,0,0,0.1);
}

.dot {
  width: 10px;
  height: 10px;
  background: #333;
  border-radius: 50%;
  display: block;
}

/* Face Rotations */
.face-1 { transform: translateZ(30px); }
.face-6 { transform: rotateY(180deg) translateZ(30px); }
.face-3 { transform: rotateX(90deg) translateZ(30px); }
.face-4 { transform: rotateX(-90deg) translateZ(30px); }
.face-2 { transform: rotateY(90deg) translateZ(30px); }
.face-5 { transform: rotateY(-90deg) translateZ(30px); }

/* Dot Layouts */
.face-1 { justify-content: center; align-items: center; }
.face-2 { flex-direction: column; justify-content: space-between; align-items: center; }
.face-3 { justify-content: space-between; }
.face-3 .dot:nth-child(2) { align-self: center; }
.face-3 .dot:nth-child(3) { align-self: flex-end; }
.face-4, .face-5, .face-6 { justify-content: space-between; align-content: space-between; }

/* Premium Gold Dice Variant */
.dice-face {
