                </button>
              </div>
            )) : <p className="empty">No outstanding debt.</p>}
          </div>
        </div>
      </div>

      <style>{`
        .financial-controls {
          padding: 1.5rem;
          margin-top: 1rem;
          background: rgba(20, 20, 25, 0.6);
