  id: string;
  name: string;
  type: 'REAL_ESTATE' | 'STOCK' | 'BUSINESS' | 'COIN';
  cost: number;
  downPayment: number;
  cashflow: number;
  shares?: number; // For stocks
  dividend?: number; // For stocks
}

export interface Liability {
  id: string;
  name: string;
  amount: number;
  payment: number;
}

export interface Profession {
  name: string;
  salary: number;
  taxes: number;
  mortgage: number;
  mortgagePayment: number;
  schoolLoan: number;
  schoolLoanPayment: number;
  carLoan: number;
  carLoanPayment: number;
  creditCard: number;
  creditCardPayment: number;
  retailDebt: number;
  retailDebtPayment: number;
  otherExpenses: number;
  perChildExpense: number;
  savings: number;
}

export interface FinancialStatement {
  // Income
  salary: number;
  passiveIncome: number;
  totalIncome: number;

  // Expenses
  taxes: number;
  homeMortgagePayment: number;
  schoolLoanPayment: number;
  carLoanPayment: number;
  creditCardPayment: number;
  retailPayment: number;
  otherExpenses: number;
  childExpenses: number;
  bankLoanPayment: number;
  totalExpenses: number;

  // Monthly Cash Flow (Payday)
  monthlyCashFlow: number;

  // Balance Sheet
